import subprocess
from dataclasses import dataclass, field
from typing import Callable

@dataclass
class Tool:
    name: str
    description: str
    fn: Callable

@dataclass
class TaskState:
    facts: dict = field(default_factory=dict)

    def get(self, key, default=None):
        return self.facts.get(key, default)

    def set(self, key, value):
        self.facts[key] = value
        return self

class TaskAutomationAgent:
    def __init__(self, goal_test, tools, max_steps=20):
        self.goal_test = goal_test
        self.tools = {t.name: t for t in tools}
        self.max_steps = max_steps
        self.log = []

    def run(self, initial_state):
        state = TaskState(facts=dict(initial_state))
        for step in range(self.max_steps):
            if self.goal_test(state):
                print('Done in ' + str(step) + ' steps')
                return state, True
            action = self._choose_action(state)
            if not action:
                print('No applicable action')
                return state, False
            print('Step ' + str(step + 1) + ': ' + action.name)
            action.fn(state)
            self.log.append(action.name)
        print('Budget exhausted')
        return state, False

    def _choose_action(self, state):
        # Greedy: pick first tool whose precondition is met
        # Real agents use an LLM or planner here
        for name, tool in self.tools.items():
            if hasattr(tool, 'precondition') and tool.precondition(state):
                return tool
        return None

# Example: automate running and fixing a test suite
def run_tests(state):
    result = subprocess.run(['python', '-m', 'pytest', '--tb=no', '-q'],
                            capture_output=True, text=True)
    passed = result.returncode == 0
    state.set('tests_pass', passed)
    state.set('test_output', result.stdout + result.stderr)

def fix_imports(state):
    # Simplified: in practice, parse test_output for ImportError lines
    state.set('imports_fixed', True)

def add_missing_module(state):
    subprocess.run(['pip', 'install', 'missing-pkg', '-q'])
    state.set('deps_installed', True)

tool_run_tests = Tool('run_tests', 'Run the test suite', run_tests)
attributes = {'precondition': lambda s: not s.get('tests_pass', False)}
tool_run_tests.__dict__.update(attributes)

goal = lambda s: s.get('tests_pass', False)
agent = TaskAutomationAgent(goal_test=goal, tools=[tool_run_tests], max_steps=5)
final, achieved = agent.run({'tests_pass': False})

import json
import time
from dataclasses import dataclass, field

@dataclass
class ActionRecord:
    step: int
    action: str
    args: dict
    result: object
    duration_ms: float
    success: bool
    error: str = ''

class ObservableAgent:
    def __init__(self, goal_test, tools, max_steps=20):
        self.goal_test = goal_test
        self.tools = tools
        self.max_steps = max_steps
        self.run_log = []

    def run(self, state):
        start = time.time()
        for step in range(self.max_steps):
            if self.goal_test(state):
                self._emit_summary(step, success=True)
                return state, True
            tool = self._select(state)
            if not tool:
                self._emit_summary(step, success=False, reason='no applicable tool')
                return state, False
            t0 = time.time()
            try:
                result = tool['fn'](state)
                record = ActionRecord(
                    step=step, action=tool['name'], args={},
                    result=result, duration_ms=(time.time()-t0)*1000,
                    success=True,
                )
            except Exception as e:
                record = ActionRecord(
                    step=step, action=tool['name'], args={},
                    result=None, duration_ms=(time.time()-t0)*1000,
                    success=False, error=str(e),
                )
            self.run_log.append(record)

    def export_log(self):
        return [vars(r) for r in self.run_log]

    def _select(self, state):
        for t in self.tools:
            if t.get('precondition', lambda s: True)(state):
                return t
        return None

    def _emit_summary(self, steps, success, reason=''):
        status = 'SUCCESS' if success else 'FAILED: ' + reason
        print('Run summary: ' + str(steps) + ' steps, ' + status)
        print('Action log:', [r.action for r in self.run_log])

import os

# Non-idempotent: appends to a file on every run
def bad_append_config(path, setting):
    with open(path, 'a') as f:
        f.write(setting + '\n')  # duplicates setting on every run

# Idempotent: checks before writing
def safe_set_config(path, setting):
    if os.path.exists(path):
        with open(path, 'r') as f:
            existing = f.read()
        if setting in existing:
            return  # already set -- no-op
    with open(path, 'a') as f:
        f.write(setting + '\n')

# Idempotent database upsert pattern
def upsert_record(db, record):
    existing = db.get(record['id'])
    if existing == record:
        return  # already up to date
    db[record['id']] = record  # replace or insert

# Idempotent file-creation
def ensure_file_exists(path, content):
    if os.path.exists(path):
        return  # already created
    with open(path, 'w') as f:
        f.write(content)

# Task agent with idempotent action wrapper
class IdempotentTaskAgent:
    def __init__(self, state_store):
        self.completed = self._load_completed(state_store)
        self.store_path = state_store

    def _load_completed(self, path):
        if os.path.exists(path):
            import json
            with open(path) as f:
                return set(json.load(f))
        return set()

    def _save_completed(self):
        import json
        with open(self.store_path, 'w') as f:
            json.dump(list(self.completed), f)

    def run_action(self, action_id, action_fn, *args):
        if action_id in self.completed:
            print('Skipping already-completed action: ' + action_id)
            return None
        result = action_fn(*args)
        self.completed.add(action_id)
        self._save_completed()
        return result

from dataclasses import dataclass, field

@dataclass
class SimulatedEnv:
    files: dict = field(default_factory=dict)
    tests_pass: bool = False
    lint_errors: list = field(default_factory=list)

    def read_file(self, path):
        return self.files.get(path, '')

    def write_file(self, path, content):
        self.files[path] = content

    def run_linter(self):
        return list(self.lint_errors)  # returns current errors

    def run_tests(self):
        return self.tests_pass

def test_lint_fix_tool():
    env = SimulatedEnv(
        files={'main.py': 'import os\nprint(1)'},
        lint_errors=['main.py:2: E501 line too long'],
    )
    assert env.run_linter() == ['main.py:2: E501 line too long']

    # Simulate the agent fixing the error
    env.lint_errors = []
    assert env.run_linter() == []
    print('test_lint_fix_tool passed')

def test_full_agent_loop():
    env = SimulatedEnv(tests_pass=False, lint_errors=['e1', 'e2'])

    # Simulate the agent working until both conditions clear
    steps = 0
    while env.lint_errors or not env.tests_pass:
        if env.lint_errors:
            env.lint_errors.pop()
        else:
            env.tests_pass = True
        steps += 1
        assert steps <= 10, 'agent did not converge'

    assert not env.lint_errors
    assert env.tests_pass
    print('test_full_agent_loop passed in ' + str(steps) + ' steps')

test_lint_fix_tool()
test_full_agent_loop()
